import{_ as o,o as r,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"50. Recall Return To Workplace","description":"","frontmatter":{"title":"50. Recall Return To Workplace","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/50-recall-return-to-workplace.md","filePath":"ebas/nurses-midwives/hours-of-work/50-recall-return-to-workplace.md"}'),a={name:"ebas/nurses-midwives/hours-of-work/50-recall-return-to-workplace.md"};function l(i,e,s,c,p,d){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_50-recall-return-to-workplace" tabindex="-1">50. Recall Return To Workplace <a class="header-anchor" href="#_50-recall-return-to-workplace" aria-label="Permalink to &quot;50. Recall Return To Workplace&quot;">​</a></h1><p><strong>50.1</strong> An Employee recalled to work during an off duty period will be paid overtime for a minimum of three hours&#39; pay at the appropriate overtime rate where that work is not continuous with the next succeeding rostered period of duty.</p><p><strong>50.2</strong> An Employee recalled to work will not be required to work the full three hours if the work to be performed is completed in a shorter period.</p><p><strong>50.3</strong> From 24 June 2024, each period of recall under this clause within an on-call period will stand alone, provided that:</p><p><strong>(a)</strong> only the first period of recall within an on-call period will result in a lower overtime penalty (if applicable under subclause 49.2(c)); and</p><p><strong>(b)</strong> consecutive periods of on-call will be treated as a single period of on-call for the purposes of (a) above.</p><p><strong>50.4</strong> Clause 50.2 above will not apply when overtime is continuous with the completion or commencement of that Employee&#39;s rostered shift.</p><p><strong>50.5</strong> The time spent travelling to and from the place of duty will be deemed to be time worked.</p><p><strong>50.6</strong> From 8 July 2024, if an Employee is recalled and is subsequently not required to commence work the Employee is entitled to the minimum payment at clause 50.1 above.</p><p><strong>50.7</strong> Emergency on-call/recall</p><p><strong>(a)</strong> An Employee rostered on call for the purposes of recall to staff an emergency in a Catheter Laboratory or Operating Theatre (including anaesthetics and recovery) will not be required to work overtime or be otherwise recalled other than for the emergency during that on-call period, subject to (b) below.</p><p><strong>(b)</strong> An Employee to whom (a) applies:</p><p><strong>(i)</strong> may be required to remain at work beyond the completion of rostered ordinary hours to conclude a procedure that commenced before the conclusion of rostered ordinary hours;</p><p><strong>(ii)</strong> will be entitled to recall to duty in the event they remain on-duty after the completion of a procedure that commenced before the conclusion of rostered ordinary hours; and</p><p><strong>(iii)</strong> from 8 July 2024, despite (ii) above, will be entitled to recall to duty if the Employee is required to work for 90 minutes or more of overtime after the conclusion of rostered ordinary hours (including where a case continues).</p><p><strong>(c)</strong> As far as practicable, and having regard to fatigue considerations, each Employer will seek to ensure that non-emergency overtime/recall will be allocated to Employees to whom (a) does not apply.</p>',16)])])}const h=o(a,[["render",l]]);export{m as __pageData,h as default};
